```class Solution {
public:
    string answerString(string word, int numFriends) {
        vector<string> v;
        for (int i = 1; i <= word.size(); ++i) {
            if (word.size() % i == 0) {
                string temp = "";
                for (int j = 0; j < word.size(); ++j) {
                    temp += word[j];
                    if ((j + 1) % i == 0 && j != word.size() - 1) {
                        v.push_back(temp);
                        temp = "";
                    }
                }
            }
        }
        sort(v.begin(), v.end(), greater<string>());
        return v[0];
    }
};
